+fn filter_by_token(items: Vec<CompletionItem>, token: &str) -> Vec<CompletionItem> {
+    let mut items = items;
+    items.sort_by(|a, b| {
+        let ka = a.sort_text.as_deref().unwrap_or(a.label.as_str());
+        let kb = b.sort_text.as_deref().unwrap_or(b.label.as_str());
+        ka.cmp(kb)
+    });
