             "processId": std::process::id(),
             "rootUri": ws_uri,
             "capabilities": {},
             "initializationOptions": {
                 "language": "hoi4",
                 "rulesCache": rules_dir.path().to_string_lossy(),
             }
         }),
     );
     write_frame(&mut child, &body).unwrap();
     let _ = read_response(&mut reader).expect("no init response");

